// Replace ALL 2026-03-30 week rows with freshly queried data (includes 3/30 + 3/31 + 4/1)
const fs = require('fs');
const dir = 'public/data/performance';

function replace330(file, newRows, keyFn) {
  const ex = JSON.parse(fs.readFileSync(dir + '/' + file));
  const without330 = ex.filter(r => r.w !== '2026-03-30');
  const merged = [...without330, ...newRows];
  merged.sort((a,b) => (a.w||'').localeCompare(b.w||'') || (a.c||'').localeCompare(b.c||'') || (a.pr||'').localeCompare(b.pr||''));
  fs.writeFileSync(dir + '/' + file, JSON.stringify(merged));
  const weeks = [...new Set(merged.map(r => r.w))].sort();
  console.log(file + ': removed ' + (ex.length - without330.length) + ', added ' + newRows.length + ' → total=' + merged.length + ', latest=' + weeks[weeks.length-1]);
}

